import argparse
import json
import random
import socket
import threading
import time
from typing import Dict, List, Tuple


class GameState:
    def __init__(self) -> None:
        self._lock = threading.Lock()
        self.server_name = "Example Game Server"
        self.map_name = "arena_alpha"
        self.mode = "deathmatch"
        self.max_players = 64
        self.tick = 0
        self.start_time = time.time()
        self.players: List[Dict] = []
        self._seed_players()

    def _seed_players(self) -> None:
        names = [
            "Alpha", "Bravo", "Charlie", "Delta", "Echo", "Foxtrot", "Ghost", "Hunter",
            "Iris", "Jinx", "Kilo", "Luna", "Mako", "Nova", "Onyx", "Pyro",
            "Quartz", "Rogue", "Shade", "Titan", "Umbra", "Viper", "Warden", "Zephyr"
        ]
        count = random.randint(8, 24)
        for i in range(count):
            self.players.append({
                "id": i + 1,
                "name": random.choice(names) + str(random.randint(1, 999)),
                "score": random.randint(0, 80),
                "ping": random.randint(18, 140),
                "team": random.choice(["red", "blue", "spectator"]),
                "alive": random.choice([True, False]),
                "x": round(random.uniform(-2048, 2048), 2),
                "y": round(random.uniform(-2048, 2048), 2),
                "z": round(random.uniform(0, 512), 2),
            })

    def update(self) -> None:
        with self._lock:
            self.tick += 1
            for p in self.players:
                p["score"] += random.choice([0, 0, 1])
                p["ping"] = max(10, min(250, p["ping"] + random.randint(-5, 5)))
                p["alive"] = random.choice([True, True, True, False])
                p["x"] = round(p["x"] + random.uniform(-10, 10), 2)
                p["y"] = round(p["y"] + random.uniform(-10, 10), 2)
                p["z"] = round(max(0, min(512, p["z"] + random.uniform(-2, 2))), 2)

    def snapshot(self) -> Dict:
        with self._lock:
            return {
                "type": "status",
                "server": {
                    "name": self.server_name,
                    "map": self.map_name,
                    "mode": self.mode,
                    "players": len(self.players),
                    "max_players": self.max_players,
                    "uptime_seconds": int(time.time() - self.start_time),
                    "tick": self.tick,
                },
                "game_state": {
                    "round_time_remaining": random.randint(30, 900),
                    "teams": {
                        "red": sum(1 for p in self.players if p["team"] == "red"),
                        "blue": sum(1 for p in self.players if p["team"] == "blue"),
                        "spectator": sum(1 for p in self.players if p["team"] == "spectator"),
                    },
                },
                "players": list(self.players),
            }


class UDPGameServer:
    def __init__(self, host: str, port: int, state: GameState) -> None:
        self.host = host
        self.port = port
        self.state = state
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.bind((self.host, self.port))
        self.running = False

    def _build_response(self) -> bytes:
        payload = self.state.snapshot()
        data = json.dumps(payload, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
        return data

    def serve_forever(self) -> None:
        self.running = True
        print(f"UDP game server listening on {self.host}:{self.port}")
        while self.running:
            try:
                data, addr = self.sock.recvfrom(65535)
                if not data:
                    continue
                msg = data.strip().decode("utf-8", errors="ignore").lower()
                if msg in ("status", "getstatus", "query", "serverinfo"):
                    response = self._build_response()
                    self.sock.sendto(response, addr)
            except KeyboardInterrupt:
                break
            except Exception:
                continue

    def close(self) -> None:
        self.running = False
        try:
            self.sock.close()
        except Exception:
            pass


def state_updater(state: GameState, interval: float) -> None:
    while True:
        time.sleep(interval)
        state.update()


def main() -> None:
    parser = argparse.ArgumentParser()
    parser.add_argument("--host", default="0.0.0.0")
    parser.add_argument("--port", type=int, default=27960)
    parser.add_argument("--update-interval", type=float, default=1.0)
    args = parser.parse_args()

    state = GameState()
    threading.Thread(target=state_updater, args=(state, args.update_interval), daemon=True).start()

    server = UDPGameServer(args.host, args.port, state)
    try:
        server.serve_forever()
    finally:
        server.close()


if __name__ == "__main__":
    main()